import { isInTypeContext } from "../../utils/scope-utils.js";
describe('scope-utils', () => {
    describe('isInTypeContext', () => {
        it('should return true when node has a TypeScript type parent', () => {
            const node = {
                type: 'Identifier',
                name: 'fetch',
                parent: {
                    type: 'TSTypeReference',
                },
            };
            expect(isInTypeContext(node)).toBe(true);
        });
        it('should return true for TSInterfaceHeritage parent', () => {
            const node = {
                type: 'Identifier',
                name: 'BaseInterface',
                parent: {
                    type: 'TSInterfaceHeritage',
                },
            };
            expect(isInTypeContext(node)).toBe(true);
        });
        it('should return true for TSClassImplements parent', () => {
            const node = {
                type: 'Identifier',
                name: 'Interface',
                parent: {
                    type: 'TSClassImplements',
                },
            };
            expect(isInTypeContext(node)).toBe(true);
        });
        it('should return true for TSTypeQuery parent', () => {
            const node = {
                type: 'Identifier',
                name: 'SomeValue',
                parent: {
                    type: 'TSTypeQuery',
                },
            };
            expect(isInTypeContext(node)).toBe(true);
        });
        it('should return true for TSQualifiedName parent', () => {
            const node = {
                type: 'Identifier',
                name: 'TypeName',
                parent: {
                    type: 'TSQualifiedName',
                },
            };
            expect(isInTypeContext(node)).toBe(true);
        });
        it('should return false when parent is not a type context', () => {
            const node = {
                type: 'Identifier',
                name: 'fetch',
                parent: {
                    type: 'CallExpression',
                },
            };
            expect(isInTypeContext(node)).toBe(false);
        });
        it('should return false when parent is undefined', () => {
            const node = {
                type: 'Identifier',
                name: 'fetch',
                parent: undefined,
            };
            expect(isInTypeContext(node)).toBe(false);
        });
        it('should return false when node has no parent property', () => {
            const node = {
                type: 'Identifier',
                name: 'fetch',
            };
            expect(isInTypeContext(node)).toBe(false);
        });
    });
});
